# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from functools import wraps
import time
import logging
from datetime import datetime

app = Flask(__name__)

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

# Elasticsearch configuration
ES_HOST = 'localhost'
ES_PORT = 9200
ES_INDEX = 'products'

# Initialize Elasticsearch client with connection pooling
es = Elasticsearch(
    [{'host': ES_HOST, 'port': ES_PORT, 'scheme': 'http'}],
    max_retries=3,
    retry_on_timeout=True,
    maxsize=25
)

# Rate limiting decorator
request_counts = {}
RATE_LIMIT = 100  # requests per minute
RATE_WINDOW = 60  # seconds

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_ip = request.remote_addr
        current_time = time.time()
        
        if client_ip not in request_counts:
            request_counts[client_ip] = []
        
        # Remove old requests outside the time window
        request_counts[client_ip] = [
            req_time for req_time in request_counts[client_ip]
            if current_time - req_time < RATE_WINDOW
        ]
        
        if len(request_counts[client_ip]) >= RATE_LIMIT:
            return jsonify({
                'error': 'Rate limit exceeded',
                'message': f'Maximum {RATE_LIMIT} requests per minute allowed'
            }), 429
        
        request_counts[client_ip].append(current_time)
        return f(*args, **kwargs)
    
    return decorated_function

# Cache for frequent searches
search_cache = {}
CACHE_TTL = 300  # 5 minutes

def get_cached_result(query, page, size):
    cache_key = f"{query}:{page}:{size}"
    if cache_key in search_cache:
        cached_data, timestamp = search_cache[cache_key]
        if time.time() - timestamp < CACHE_TTL:
            return cached_data
        else:
            del search_cache[cache_key]
    return None

def set_cached_result(query, page, size, result):
    cache_key = f"{query}:{page}:{size}"
    search_cache[cache_key] = (result, time.time())

@app.route('/api/search', methods=['GET'])
@rate_limit
def search_products():
    try:
        # Get query parameters
        query = request.args.get('q', '').strip()
        page = int(request.args.get('page', 1))
        size = int(request.args.get('size', 20))
        sort_by = request.args.get('sort', 'relevance')
        min_price = request.args.get('min_price')
        max_price = request.args.get('max_price')
        category = request.args.get('category')
        
        # Validate input
        if not query:
            return jsonify({
                'error': 'Missing query parameter',
                'message': 'Please provide a search query using the q parameter'
            }), 400
        
        if len(query) < 2:
            return jsonify({
                'error': 'Query too short',
                'message': 'Search query must be at least 2 characters'
            }), 400
        
        if size > 100:
            size = 100
        
        if page < 1:
            page = 1
        
        # Check cache
        cached_result = get_cached_result(query, page, size)
        if cached_result:
            logger.info(f"Cache hit for query: {query}")
            cached_result['cached'] = True
            return jsonify(cached_result), 200
        
        # Build Elasticsearch query
        from_offset = (page - 1) * size
        
        # Multi-match query for better relevance
        must_clauses = [
            {
                "multi_match": {
                    "query": query,
                    "fields": [
                        "name^3",
                        "description^2",
                        "category",
                        "brand^2",
                        "tags"
                    ],
                    "type": "best_fields",
                    "fuzziness": "AUTO",
                    "operator": "or"
                }
            }
        ]
        
        # Add filters
        filter_clauses = []
        
        if min_price or max_price:
            price_range = {}
            if min_price:
                price_range['gte'] = float(min_price)
            if max_price:
                price_range['lte'] = float(max_price)
            filter_clauses.append({
                "range": {
                    "price": price_range
                }
            })
        
        if category:
            filter_clauses.append({
                "term": {
                    "category.keyword": category
                }
            })
        
        # Add availability filter
        filter_clauses.append({
            "term": {
                "in_stock": True
            }
        })
        
        # Build final query
        es_query = {
            "bool": {
                "must": must_clauses,
                "filter": filter_clauses
            }
        }
        
        # Determine sort order
        sort_options = []
        if sort_by == 'price_asc':
            sort_options = [{"price": {"order": "asc"}}]
        elif sort_by == 'price_desc':
            sort_options = [{"price": {"order": "desc"}}]
        elif sort_by == 'newest':
            sort_options = [{"created_at": {"order": "desc"}}]
        elif sort_by == 'popular':
            sort_options = [{"popularity_score": {"order": "desc"}}]
        else:  # relevance (default)
            sort_options = ["_score"]
        
        # Execute search with timeout
        search_params = {
            "index": ES_INDEX,
            "body": {
                "query": es_query,
                "from": from_offset,
                "size": size,
                "sort": sort_options,
                "_source": [
                    "id", "name", "description", "price", 
                    "image_url", "category", "brand", 
                    "rating", "in_stock", "discount"
                ],
                "highlight": {
                    "fields": {
                        "name": {},
                        "description": {}
                    },
                    "pre_tags": ["<em>"],
                    "post_tags": ["</em>"]
                }
            },
            "timeout": "5s"
        }
        
        start_time = time.time()
        response = es.search(**search_params)
        search_time = time.time() - start_time
        
        # Format results
        products = []
        for hit in response['hits']['hits']:
            product = hit['_source']
            product['score'] = hit['_score']
            
            # Add highlights if available
            if 'highlight' in hit:
                product['highlights'] = hit['highlight']
            
            products.append(product)
        
        # Build response
        total_hits = response['hits']['total']['value']
        total_pages = (total_hits + size - 1) // size
        
        result = {
            'query': query,
            'total': total_hits,
            'page': page,
            'size': size,
            'total_pages': total_pages,
            'products': products,
            'search_time': round(search_time * 1000, 2),
            'cached': False
        }
        
        # Cache the result
        set_cached_result(query, page, size, result.copy())
        
        # Log search
        logger.info(f"Search query: '{query}' - Results: {total_hits} - Time: {search_time:.3f}s")
        
        return jsonify(result), 200
        
    except ValueError as e:
        logger.error(f"Validation error: {str(e)}")
        return jsonify({
            'error': 'Invalid parameter',
            'message': str(e)
        }), 400
    
    except Exception as e:
        logger.error(f"Search error: {str(e)}")
        return jsonify({
            'error': 'Search failed',
            'message': 'An error occurred while processing your search'
        }), 500

@app.route('/api/search/suggest', methods=['GET'])
@rate_limit
def suggest():
    try:
        query = request.args.get('q', '').strip()
        
        if not query or len(query) < 2:
            return jsonify({'suggestions': []}), 200
        
        # Suggest query using completion suggester
        response = es.search(
            index=ES_INDEX,
            body={
                "suggest": {
                    "product-suggest": {
                        "prefix": query,
                        "completion": {
                            "field": "name_suggest",
                            "size": 10,
                            "skip_duplicates": True
                        }
                    }
                }
            }
        )
        
        suggestions = []
        for option in response['suggest']['product-suggest'][0]['options']:
            suggestions.append({
                'text': option['text'],
                'score': option['_score']
            })
        
        return jsonify({'suggestions': suggestions}), 200
        
    except Exception as e:
        logger.error(f"Suggestion error: {str(e)}")
        return jsonify({'suggestions': []}), 200

@app.route('/api/health', methods=['GET'])
def health_check():
    try:
        es.cluster.health()
        return jsonify({
            'status': 'healthy',
            'elasticsearch': 'connected',
            'timestamp': datetime.utcnow().isoformat()
        }), 200
    except:
        return jsonify({
            'status': 'unhealthy',
            'elasticsearch': 'disconnected',
            'timestamp': datetime.utcnow().isoformat()
        }), 503

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, threaded=True)